class Solution {
    public int countGoodStrings(int low, int high, int zero, int one) {
        int MOD = 1000000007;
        int[] dp = new int[high + 1];
        dp[0] = 1;
        for (int i = 1; i <= high; i++) {
            int ways = 0;
            if (i >= zero) {
                ways += dp[i - zero];
            }
            if (i >= one) {
                ways += dp[i - one];
            }
            dp[i] = ways % MOD;
        }
        int sum = 0;
        for (int l = low; l <= high; l++) {
            sum = (sum + dp[l]) % MOD;
        }
        return sum;
    }
}

